$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

$landingBase64 = @"

"@

$cadastroBase64 = @"

"@

$landingContent = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($landingBase64.Trim()))
$cadastroContent = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($cadastroBase64.Trim()))

New-Item -ItemType Directory -Force "app\cadastro" | Out-Null

[System.IO.File]::WriteAllText((Join-Path $project "app\page.tsx"), $landingContent, $utf8NoBom)
[System.IO.File]::WriteAllText((Join-Path $project "app\cadastro\page.tsx"), $cadastroContent, $utf8NoBom)

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host "Contraste da landing e cadastro atualizado para valorizar a logo." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
